#include <stdio.h>
#include <string.h>
#include <stdbool.h>
#define MAXN 1000005

int T, N;
char S[MAXN];

bool isYalalovichik(char *s) {
    int len = strlen(s);
    for (int i = 0; i < len; i++) {
        for (int j = i + 1; j <= len; j++) {
            char sub[j - i];
            strncpy(sub, s + i, j - i);
            sub[j - i] = '\0';
            bool found = false;
            for (int mask = 1; mask < (1 << len); mask++) {
                char subseq[j - i];
                int k = 0;
                for (int l = 0; l < len; l++) {
                    if ((mask & (1 << l))) {
                        subseq[k++] = s[l];
                    }
                }
                subseq[k] = '\0';
                if (strcmp(sub, subseq) == 0) {
                    found = true;
                    break;
                }
            }
            if (!found) return false;
        }
    }
    return true;
}

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        scanf("%s", S);
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j <= N; j++) {
                char sub[j - i];
                strncpy(sub, S + i, j - i);
                sub[j - i] = '\0';
                if (isYalalovichik(sub)) count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

