import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String S = sc.next();
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j <= N; j++) {
                    String sub = S.substring(i, j);
                    if (isYalalovichik(sub)) count++;
                }
            }
            System.out.println(count);
        }
    }

    public static boolean isYalalovichik(String s) {
        int len = s.length();
        for (int i = 0; i < len; i++) {
            for (int j = i + 1; j <= len; j++) {
                String sub = s.substring(i, j);
                boolean found = false;
                for (int mask = 1; mask < (1 << len); mask++) {
                    StringBuilder subseq = new StringBuilder();
                    for (int l = 0; l < len; l++) {
                        if ((mask & (1 << l)) != 0) {
                            subseq.append(s.charAt(l));
                        }
                    }
                    if (sub.equals(subseq.toString())) {
                        found = true;
                        break;
                    }
                }
                if (!found) return false;
            }
        }
        return true;
    }
}

